      }
    }
  }

  const result: Cell[] = [];
  for (const [key, count] of neighborCounts) {
    const [x, y] = key.split(",").map(Number) as Cell;
    if (count === 3 || (count === 2 && alive.has(key))) {
      result.push([x, y]);
    }
  }

  return result;
};

